+      while (Node) {
+        BasicBlock *DomBB = Node->getBlock();
+        if (BranchInst *BI = dyn_cast<BranchInst>(DomBB->getTerminator())) {
+          if (BI->isConditional()) {
+            if (ICmpInst *CI = dyn_cast<ICmpInst>(BI->getCondition())) {
+              if (CI->getOperand(0) == Op || CI->getOperand(1) == Op) {
+                return true;
+              }
+            }
+          }
+        }
+        Node = Node->getIDom();
+      }
+      return false;
+    };
